   150→interface StreamMessage {
   151→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
   152→  subtype?: string;
   153→  role?: 'assistant' | 'user';
   154→  event?: {
   155→    type: string;
   156→    delta?: {
   157→      type: string;
   158→      text?: string;
