   182→  let depth = 0;
   183→  for (let i = jsonStart; i < output.length; i++) {
   184→    if (output[i] === '{') depth++;
   185→    if (output[i] === '}') depth--;
   186→    if (depth === 0) {
   187→      try {
   188→        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
   189→        if (typeof parsed.exit === 'boolean') {
   190→          return parsed as RalphStatus;
   191→        }
   192→      } catch {}
   193→      return null;
   194→    }
   195→  }
   196→  return null;
   197→}
