   208→async function checkDependencies(): Promise<void> {
   209→  const result = await Bun.$`which claude`.quiet().nothrow();
   210→  if (result.exitCode !== 0) {
   211→    syslog("ERROR: 'claude' CLI not found. Install Claude Code.", 'red');
   212→    process.exit(1);
   213→  }
   214→
   215→  if (!(await Bun.file(CONFIG.progressFile).exists())) {
   216→    syslog(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
   217→    process.exit(1);
   218→  }
