   221→interface IterationResult {
   222→  output: string;
   223→  exitCode: number;
   224→  timedOut: boolean;
   225→}
   226→
   227→async function runIteration(): Promise<IterationResult> {
   228→  syslog('Executing Claude Code...');
   229→
   230→  const proc = Bun.spawn(
   231→    [
   232→      'claude',
   233→      '-p',
   234→      TASK_PROMPT,
   235→      '--verbose',
   236→      '--debug',
   237→      '--dangerously-skip-permissions',
   238→      '--output-format',
   239→      'stream-json',
   240→      '--include-partial-messages',
   241→      '--model=opus',
   242→    ],
   243→    {
   244→      cwd: process.cwd(),
   245→      env: process.env,
   246→      stdout: 'pipe',
   247→      stderr: 'inherit',
   248→    },
   249→  );
   250→
   251→  currentProc = proc;
   252→
   253→  const chunks: string[] = [];
   254→  let timedOut = false;
   255→  const decoder = new TextDecoder();
   256→  let buffer = '';
   257→  let blockHasContent = false;
   258→
   259→  const timeoutId = setTimeout(() => {
   260→    timedOut = true;
   261→    syslog('Iteration timeout reached. Killing process...', 'yellow');
   262→    killCurrentProc();
   263→  }, CONFIG.iterationTimeout);
   264→
   265→  const reader = proc.stdout.getReader();
   266→
   267→  try {
   268→    while (true) {
   269→      const { done, value } = await reader.read();
   270→      if (done) break;
   271→
   272→      buffer += decoder.decode(value, { stream: true });
   273→
   274→      const lines = buffer.split('\n');
   275→      buffer = lines.pop() || '';
   276→
   277→      for (const line of lines) {
   278→        if (!line.trim()) continue;
   279→
   280→        let msg: StreamMessage;
   281→        try {
   282→          msg = JSON.parse(line);
   283→        } catch {
   284→          continue;
   285→        }
   286→
   287→        if (msg.type === 'stream_event') {
   288→          const evt = msg.event;
   289→          if (!evt) continue;
   290→
   291→          if (evt.type === 'content_block_start') {
   292→            blockHasContent = false;
   293→          } else if (evt.type === 'content_block_delta') {
   294→            const text = evt.delta?.text;
   295→            if (text) {
   296→              print(text);
   297→              chunks.push(text);
   298→              blockHasContent = true;
   299→            }
   300→          } else if (evt.type === 'content_block_stop' && blockHasContent) {
   301→            print('\n');
   302→            chunks.push('\n');
   303→            blockHasContent = false;
   304→          }
   305→          continue;
   306→        }
   307→
   308→        if (msg.type === 'assistant' || msg.type === 'message') {
   309→          // Content already streamed via content_block_delta events.
   310→          // Only print here as fallback if no streaming occurred.
   311→          const blocks = msg.message?.content ?? msg.content;
   312→          if (!Array.isArray(blocks)) continue;
   313→
   314→          for (const block of blocks) {
   315→            if (block.type === 'text' && block.text && chunks.length === 0) {
   316→              print(block.text);
   317→              chunks.push(block.text);
   318→              print('\n');
   319→              chunks.push('\n');
   320→            }
   321→          }
   322→          continue;
   323→        }
   324→
   325→        if (msg.type === 'user') {
   326→          const blocks = msg.message?.content ?? msg.content;
   327→          if (!Array.isArray(blocks)) continue;
   328→
   329→          for (const block of blocks) {
   330→            //
   331→            // Handling tool result
   332→            if (block.type === 'tool_result' && block.content) {
   333→              const rawContent =
   334→                typeof block.content === 'string'
   335→                  ? block.content
   336→                  : block.content
   337→                      .map(c => c.text ?? '')
   338→                      .filter(Boolean)
   339→                      .join('\n');
   340→
   341→              if (!rawContent) continue;
   342→
   343→              let trimmed = rawContent.trim().slice(0, 320);
   344→
   345→              const toolResult =
   346→                trimmed && trimmed !== rawContent
   347→                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
   348→                  : rawContent;
   349→
   350→              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
   351→              chunks.push('\n', rawContent, '\n');
   352→            }
   353→          }
   354→          continue;
   355→        }
   356→
   357→        if (msg.type === 'result' && msg.result) {
   358→          if (chunks.length === 0) {
   359→            chunks.push(msg.result);
   360→          }
   361→        }
   362→      }
   363→    }
   364→
   365→    if (buffer.trim()) {
   366→      try {
   367→        const msg: StreamMessage = JSON.parse(buffer);
   368→        if (msg.type === 'result' && msg.result && chunks.length === 0) {
   369→          chunks.push(msg.result);
   370→        }
   371→      } catch {}
   372→    }
   373→  } finally {
   374→    clearTimeout(timeoutId);
   375→    reader.releaseLock();
   376→    currentProc = null;
   377→    logBuffer.flush();
   378→  }
   379→
   380→  const output = chunks.join('');
   381→
   382→  if (timedOut) {
   383→    return {
   384→      output,
   385→      exitCode: 124,
   386→      timedOut: true,
   387→    };
   388→  }
   389→
   390→  const exitCode = await proc.exited;
   391→  println();
   392→  return {
   393→    output,
   394→    exitCode,
   395→    timedOut: false,
   396→  };
   397→}
   398→
   399→function printHeader(): void {
   400→  println();
   401→  println('==========================================', 'blue');
   402→  println('   Ralph Loop - Bun.js Edition', 'blue');
   403→  println('==========================================', 'blue');
   404→  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
   405→  println(`Log file:       ${chalk.yellow(CONFIG.logFile)}`);
   406→  println(
   407→    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
   408→  );
   409→  println(
   410→    `Iter timeout:   ${chalk.yellow(`${CONFIG.iterationTimeout / 60_000}min`)}`,
   411→  );
   412→  println();
   413→}
   414→
   415→async function main(): Promise<void> {
   416→  let cleanupCalled = false;
   417→
   418→  const cleanup = (signal: string) => {
   419→    if (cleanupCalled) return;
   420→    cleanupCalled = true;
   421→    println();
   422→    syslog(`Interrupted by ${signal}. Cleaning up...`);
   423→    killCurrentProc();
   424→    logBuffer.dispose();
   425→    process.exit(signal === 'SIGINT' ? 130 : 143);
   426→  };
   427→
   428→  process.on('SIGINT', () => cleanup('SIGINT'));
   429→  process.on('SIGTERM', () => cleanup('SIGTERM'));
   430→
   431→  await checkDependencies();
   432→
   433→  writeFileSync(CONFIG.logFile, '');
   434→
   435→  printHeader();
   436→  syslog('Starting automated task loop...');
   437→
   438→  let consecutiveFailures = 0;
   439→  const MAX_CONSECUTIVE_FAILURES = 3;
   440→
   441→  for (let iteration = 1; iteration <= CONFIG.maxIterations; iteration++) {
   442→    println();
   443→    println('==========================================', 'green');
   444→    syslog(`Iteration #${iteration} / ${CONFIG.maxIterations}`, 'green');
   445→    println('==========================================', 'green');
   446→    println();
   447→
   448→    const { output, exitCode, timedOut } = await runIteration();
   449→
   450→    if (exitCode === 0) {
   451→      syslog('Claude Code completed successfully', 'green');
   452→      consecutiveFailures = 0;
   453→    } else {
   454→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
   455→      consecutiveFailures++;
   456→    }
   457→
   458→    if (consecutiveFailures >= MAX_CONSECUTIVE_FAILURES) {
   459→      println();
   460→      println('==========================================', 'red');
   461→      syslog(
   462→        `${MAX_CONSECUTIVE_FAILURES} consecutive failures — aborting loop`,
   463→        'red',
   464→      );
   465→      println('==========================================', 'red');
   466→      logBuffer.dispose();
   467→      process.exit(1);
   468→    }
   469→
   470→    const status = parseRalphStatus(output);
   471→
   472→    if (status?.exit) {
   473→      println();
   474→      println('==========================================', 'green');
   475→      syslog('ALL TASKS COMPLETED!', 'green');
   476→      syslog(`Final task:      ${status.task}`, 'green');
   477→      syslog(`Remaining:       ${status.remaining}`, 'green');
   478→      syslog(`Total iterations: ${iteration}`, 'green');
   479→      println('==========================================', 'green');
   480→      logBuffer.dispose();
   481→      process.exit(0);
   482→    }
   483→
   484→    if (status) {
   485→      syslog(
   486→        `Task done: "${status.task}" — ${status.remaining} remaining`,
   487→        'blue',
   488→      );
   489→    } else if (!timedOut && exitCode === 0) {
   490→      syslog(
   491→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
   492→        'yellow',
   493→      );
   494→    }
   495→
   496→    if (iteration < CONFIG.maxIterations) {
   497→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
   498→      println();
   499→      syslog(`Waiting ${delaySec}s before next iteration...`);
   500→      await Bun.sleep(CONFIG.delayBetweenIterations);
   501→    }
   502→  }
   503→
   504→  println();
   505→  println('==========================================', 'red');
   506→  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
   507→  syslog('Loop stopped — tasks may still be pending', 'red');
   508→  println('==========================================', 'red');
   509→  logBuffer.dispose();
   510→  process.exit(1);
   511→}
   512→
   513→main();
